package.preload["engine.containment"] = function()
-- engine/containment/init.lua
-- Four-layer containment validator with weight checking and multi-surface support.
--
-- Layers:
--   1. Container identity -- is the target a container at all?
--   2. Physical size -- does the item physically fit?
--   3. Capacity -- is there room (by size and weight)?
--   4. Category accept/reject -- does the container allow this type of item?
--
-- Multi-surface: when a container has `surfaces`, the validator targets a
-- specific surface (top, inside, underneath, etc.) instead of root-level fields.

local containment = {}

-- Helper: get the containment zone (surface or root) for a container.
-- Returns the zone table and nil, or nil and an error string.
local function get_zone(container_obj, surface_name)
  if container_obj.surfaces and surface_name then
    local zone = container_obj.surfaces[surface_name]
    if not zone then
      return nil, "there is no '" .. surface_name .. "' on " .. (container_obj.name or container_obj.id)
    end
    if zone.accessible == false then
      return nil, "the " .. surface_name .. " of " .. (container_obj.name or container_obj.id) .. " is not accessible"
    end
    return zone, nil
  end

  -- No surfaces defined or no surface specified -- fall back to root-level fields
  if container_obj.surfaces and not surface_name then
    return nil, "you need to specify where on " .. (container_obj.name or container_obj.id) .. " (e.g. top, inside)"
  end

  -- Root-level container fields
  return {
    capacity = container_obj.capacity or 0,
    max_item_size = container_obj.max_item_size,
    weight_capacity = container_obj.weight_capacity,
    contents = container_obj.contents or {},
    accept = container_obj.accept,
    reject = container_obj.reject,
  }, nil
end

-- Helper: sum weights of contents in a zone, using the registry to look up each item.
local function contents_weight(zone, registry)
  local total = 0
  if not zone.contents or not registry then return total end
  for _, item_id in ipairs(zone.contents) do
    local obj = registry:get(item_id)
    if obj then
      total = total + (obj.weight or 0)
    end
  end
  return total
end

-- Helper: sum sizes of contents in a zone, using the registry.
local function contents_size(zone, registry)
  local total = 0
  if not zone.contents or not registry then return total end
  for _, item_id in ipairs(zone.contents) do
    local obj = registry:get(item_id)
    if obj then
      total = total + (obj.size or 0)
    end
  end
  return total
end

-- can_contain(item, container_obj, surface_name, registry)
--   -> true, nil  |  false, reason_string
--
-- Validates all four layers. `surface_name` is optional (nil for root-level).
-- `registry` is optional but required for weight checking.
function containment.can_contain(item, container_obj, surface_name, registry)
  -- Layer 0: Self-containment guard (BUG-036b)
  if item == container_obj then
    return false, "You can't put something inside itself."
  end

  -- Layer 1: Container identity
  if container_obj.surfaces then
    -- Multi-surface objects are containers by definition
  elseif not container_obj.container then
    return false, (container_obj.name or container_obj.id) .. " is not a container"
  end

  -- Get the target zone
  local zone, zone_err = get_zone(container_obj, surface_name)
  if not zone then
    return false, zone_err
  end

  -- Layer 2: Physical size
  local item_size = item.size or 1
  if zone.max_item_size and item_size > zone.max_item_size then
    return false, (item.name or item.id) .. " is too large to fit"
  end

  -- Layer 3a: Size capacity
  local used_size = contents_size(zone, registry)
  local capacity = zone.capacity or 0
  if capacity > 0 and (used_size + item_size) > capacity then
    return false, "There is not enough room on " .. (container_obj.name or "that") .. "."
  end

  -- Layer 3b: Weight capacity
  local item_weight = item.weight or 0
  if zone.weight_capacity and zone.weight_capacity > 0 then
    local used_weight = contents_weight(zone, registry)
    if (used_weight + item_weight) > zone.weight_capacity then
      return false, (item.name or item.id) .. " is too heavy"
    end
  end

  -- Layer 4: Category accept/reject
  if item.categories and type(item.categories) == "table" then
    -- Reject list: if item has any rejected category, deny
    if zone.reject and type(zone.reject) == "table" then
      for _, cat in ipairs(item.categories) do
        for _, rejected in ipairs(zone.reject) do
          if cat == rejected then
            return false, (item.name or item.id) .. " cannot be placed there"
          end
        end
      end
    end

    -- Accept list: if specified, item must have at least one accepted category
    if zone.accept and type(zone.accept) == "table" and #zone.accept > 0 then
      local accepted = false
      for _, cat in ipairs(item.categories) do
        for _, allowed in ipairs(zone.accept) do
          if cat == allowed then
            accepted = true
            break
          end
        end
        if accepted then break end
      end
      if not accepted then
        return false, (item.name or item.id) .. " does not belong there"
      end
    end
  end

  return true, nil
end

return containment

end

package.preload["engine.display"] = function()
-- engine/display.lua
-- Word-wrap utility for clean terminal output.
-- Wraps long lines at word boundaries to prevent terminal-level character
-- splitting (which can duplicate characters at wrap points on some terminals).
--
-- When display.ui is set to an active UI module, print() routes through
-- ui.output() instead of the raw terminal.  This lets the split-screen UI
-- own all output without changing any verb handler code.

local display = {}

display.WIDTH = 78

-- Set this to the engine.ui module after ui.init() succeeds.
-- When non-nil and ui.is_enabled(), print() routes through ui.output().
display.ui = nil

-- word_wrap(text, width) -> string
-- Splits text at word boundaries. Preserves existing newlines and leading
-- whitespace (for indented bullet lists like "  a tallow candle").
function display.word_wrap(text, width)
    width = width or display.WIDTH
    if not text or text == "" then return "" end

    local output = {}
    -- Split on existing newlines, wrap each line independently
    for segment in (text .. "\n"):gmatch("(.-)\n") do
        if segment == "" then
            output[#output + 1] = ""
        else
            local indent = segment:match("^(%s*)") or ""
            local content = segment:sub(#indent + 1)
            if #indent + #content <= width then
                output[#output + 1] = segment
            else
                local line = indent
                for word in content:gmatch("%S+") do
                    if line == indent then
                        line = indent .. word
                    elseif #line + 1 + #word > width then
                        output[#output + 1] = line
                        line = indent .. word
                    else
                        line = line .. " " .. word
                    end
                end
                if line ~= indent then
                    output[#output + 1] = line
                end
            end
        end
    end

    -- The gmatch pattern adds a trailing empty string from the appended "\n";
    -- remove it so we don't inject a phantom blank line.
    if #output > 0 and output[#output] == "" and not text:match("\n$") then
        table.remove(output)
    end

    return table.concat(output, "\n")
end

-- install() — replaces the global print with a word-wrapping version.
-- When display.ui is active, output routes through the split-screen UI.
-- Call once at startup (before the game loop).
function display.install()
    local original_print = _G.print
    _G.print = function(...)
        local n = select("#", ...)
        local parts = {}
        for i = 1, n do
            parts[i] = tostring(select(i, ...))
        end
        local text = table.concat(parts, "\t")

        if display.ui and display.ui.is_enabled() then
            -- Route through split-screen UI (it does its own word-wrap)
            display.ui.output(text)
        else
            original_print(display.word_wrap(text))
        end
    end
end

return display

end

package.preload["engine.fsm"] = function()
-- engine/fsm/init.lua
-- Table-driven FSM engine for object state management.
-- Objects with inline `states` and `_state` fields are managed by this system.
-- FSM definitions live INSIDE the object file (one file = one object = one FSM).
-- Non-FSM objects are unaffected (backward compatible).

local fsm = {}

-- Material registry (lazy-loaded on first threshold check)
local _materials
local function get_materials()
    if _materials then return _materials end
    local ok, mod = pcall(require, "engine.materials")
    if ok then _materials = mod end
    return _materials
end

-- Active timed events: keyed by object ID
-- Each entry: { state, remaining, event, to_state }
fsm.active_timers = {}

-- Paused timers for objects in unloaded rooms
fsm.paused_timers = {}

-- Check if an object has inline FSM data.
-- Returns the object itself as the definition, or nil.
function fsm.load(obj)
    if type(obj) == "table" and obj.states then
        return obj
    end
    return nil
end

-- Apply transition-level mutations to an object instance.
-- Supports: direct values, functions (computed from current), and list ops (add/remove).
local function apply_mutations(obj, mutations)
    if not mutations then return end
    for k, v in pairs(mutations) do
        if type(v) == "function" then
            obj[k] = v(obj[k])
        elseif type(v) == "table" and (v.add ~= nil or v.remove ~= nil) then
            local list = obj[k]
            if type(list) ~= "table" then list = {}; obj[k] = list end
            if v.remove then
                for i = #list, 1, -1 do
                    if list[i] == v.remove then table.remove(list, i) end
                end
            end
            if v.add then
                local found = false
                for _, item in ipairs(list) do
                    if item == v.add then found = true; break end
                end
                if not found then list[#list + 1] = v.add end
            end
        else
            obj[k] = v
        end
    end
end

-- Apply state properties to an object, preserving containment and identity.
-- Removes old state-specific keys, then applies new state properties.
-- Base properties (not defined in any state) persist untouched.
local function apply_state(obj, new_state_name, old_state_name)
    local new_state = obj.states[new_state_name]
    if not new_state then return false end

    -- Save containment data BEFORE cleanup (surfaces, contents, location)
    local saved_surface_contents = {}
    if obj.surfaces then
        for sname, zone in pairs(obj.surfaces) do
            saved_surface_contents[sname] = zone.contents or {}
        end
    end
    local saved_contents = obj.contents
    local saved_location = obj.location

    -- Remove old state-specific keys (skip engine-only keys)
    if old_state_name and obj.states[old_state_name] then
        for k in pairs(obj.states[old_state_name]) do
            if k ~= "on_tick" and k ~= "terminal" then
                obj[k] = nil
            end
        end
    end

    -- Apply new state properties
    for k, v in pairs(new_state) do
        if k == "on_tick" or k == "terminal" then
            -- Engine-only: not applied to the object
        elseif k == "surfaces" then
            -- Rebuild surfaces with new structure but preserved contents
            obj.surfaces = {}
            for sname, zone in pairs(v) do
                obj.surfaces[sname] = {}
                for zk, zv in pairs(zone) do
                    if zk ~= "contents" then
                        obj.surfaces[sname][zk] = zv
                    end
                end
                obj.surfaces[sname].contents = saved_surface_contents[sname] or {}
            end
        else
            obj[k] = v
        end
    end

    -- Restore containment
    obj.location = saved_location
    if saved_contents and not obj.surfaces then
        obj.contents = saved_contents
    end
    obj._state = new_state_name
    return true
end

-- Return available (non-auto) transitions from the object's current state.
function fsm.get_transitions(obj)
    if not obj or not obj.states or not obj._state then return {} end
    local result = {}
    for _, t in ipairs(obj.transitions or {}) do
        if t.from == obj._state and t.trigger ~= "auto" then
            result[#result + 1] = t
        end
    end
    return result
end

-- Transition an object to target_state. Returns transition table on success,
-- or nil + error code on failure. Optional context table for guard checks.
-- verb_hint narrows transition search when multiple transitions share a target.
function fsm.transition(registry, obj_id, target_state, context, verb_hint)
    local obj = registry:get(obj_id)
    if not obj or not obj.states or not obj._state then
        return nil, "not_fsm"
    end

    local cur = obj.states[obj._state]
    if cur and cur.terminal then return nil, "terminal" end

    -- Find a matching transition (prefer verb_hint when given)
    local trans
    for _, t in ipairs(obj.transitions or {}) do
        if t.from == obj._state and t.to == target_state and t.trigger ~= "auto" then
            if not verb_hint or t.verb == verb_hint then
                trans = t
                break
            end
            -- Also check aliases for verb_hint
            if verb_hint and t.aliases then
                for _, a in ipairs(t.aliases) do
                    if a == verb_hint then trans = t; break end
                end
                if trans then break end
            end
        end
    end
    -- Fallback: if verb_hint didn't match, pick the first available transition
    if not trans then
        for _, t in ipairs(obj.transitions or {}) do
            if t.from == obj._state and t.to == target_state and t.trigger ~= "auto" then
                trans = t
                break
            end
        end
    end
    if not trans then return nil, "no_transition" end

    -- Guard: requires_property on context.target
    if trans.requires_property then
        local target = context and context.target
        if not target or not target[trans.requires_property] then
            return nil, "requires_property", trans
        end
    end

    -- Guard: custom function
    if trans.guard and not trans.guard(obj, context) then
        return nil, "guard_failed", trans
    end

    local old_state = obj._state
    -- Stop timer for the old state (extinguish, etc.)
    fsm.stop_timer(obj_id)
    apply_state(obj, target_state, old_state)
    apply_mutations(obj, trans.mutate)
    if trans.on_transition then trans.on_transition(obj, context) end
    -- Start timer for the new state if it has timed_events
    fsm.start_timer(registry, obj_id)
    return trans
end

-- Check property thresholds for auto-transitions.
-- Thresholds are declarative: { property = "temperature", above = 62, transition = "melting" }
-- The property is checked against env_context values.
-- Optional: above_material / below_material resolves the limit from the object's material.
-- Returns a message string if a threshold transition fires, nil otherwise.
local function check_thresholds(registry, obj, obj_id, env_context)
    if not obj.thresholds or not env_context then return nil end

    local mat = nil
    if obj.material then
        local mats = get_materials()
        if mats then mat = mats.get(obj.material) end
    end

    for _, threshold in ipairs(obj.thresholds) do
        local env_value = env_context[threshold.property]
        if env_value ~= nil then
            local crossed = false

            -- Direct numeric threshold: above / below
            if threshold.above and env_value > threshold.above then
                crossed = true
            elseif threshold.below and env_value < threshold.below then
                crossed = true
            end

            -- Material-referenced threshold: above_material / below_material
            if not crossed and mat then
                if threshold.above_material then
                    local limit = mat[threshold.above_material]
                    if limit and env_value > limit then crossed = true end
                elseif threshold.below_material then
                    local limit = mat[threshold.below_material]
                    if limit and env_value < limit then crossed = true end
                end
            end

            if crossed and threshold.transition then
                -- Find a matching transition from current state to the threshold target
                for _, t in ipairs(obj.transitions or {}) do
                    if t.from == obj._state and t.to == threshold.transition then
                        local old_state = obj._state
                        fsm.stop_timer(obj_id)
                        apply_state(obj, t.to, old_state)
                        apply_mutations(obj, t.mutate)
                        if t.on_transition then t.on_transition(obj, env_context) end
                        fsm.start_timer(registry, obj_id)
                        return t.message or threshold.message
                    end
                end
            end
        end
    end
    return nil
end

-- Process auto-transitions (burn countdown, duration expiry, threshold checks).
-- Returns a message string if a transition or warning fired, nil otherwise.
-- Optional env_context: room environmental state for threshold checking.
function fsm.tick(registry, obj_id, env_context)
    local obj = registry:get(obj_id)
    if not obj or not obj.states or not obj._state then return nil end

    -- Step 1: existing on_tick callback (legacy burn countdown, etc.)
    local state = obj.states[obj._state]
    if state and state.on_tick then
        local result = state.on_tick(obj)
        if result then
            if result.warning then return result.warning end
            if result.trigger then
                for _, t in ipairs(obj.transitions or {}) do
                    if t.from == obj._state and t.trigger == "auto"
                       and t.condition == result.trigger then
                        apply_state(obj, t.to, obj._state)
                        apply_mutations(obj, t.mutate)
                        return t.message
                    end
                end
            end
        end
    end

    -- Step 2: threshold checking (material property-based auto-transitions)
    local threshold_msg = check_thresholds(registry, obj, obj_id, env_context)
    if threshold_msg then return threshold_msg end

    return nil
end

-- Start a timed event for an object if its current state has timed_events.
-- Uses remaining_burn for candle-style partial timers, otherwise the delay from metadata.
function fsm.start_timer(registry, obj_id)
    local obj = registry:get(obj_id)
    if not obj or not obj.states or not obj._state then return end

    local state = obj.states[obj._state]
    if not state or not state.timed_events then return end

    local te = state.timed_events[1]  -- first timed event
    if not te then return end

    -- Use remaining_burn if the object tracks partial burn (candle pattern)
    local delay = te.delay
    if obj.remaining_burn and obj.remaining_burn > 0 then
        delay = obj.remaining_burn
    end

    fsm.active_timers[obj_id] = {
        state = obj._state,
        remaining = delay,
        event = te.event,
        to_state = te.to_state,
    }
end

-- Stop/remove the timer for an object (e.g., on extinguish or room unload).
function fsm.stop_timer(obj_id)
    fsm.active_timers[obj_id] = nil
end

-- Pause a timer, preserving remaining time for later resume.
function fsm.pause_timer(obj_id)
    local timer = fsm.active_timers[obj_id]
    if timer then
        fsm.paused_timers[obj_id] = timer
        fsm.active_timers[obj_id] = nil
    end
end

-- Resume a paused timer.
function fsm.resume_timer(obj_id)
    local timer = fsm.paused_timers[obj_id]
    if timer then
        fsm.active_timers[obj_id] = timer
        fsm.paused_timers[obj_id] = nil
    end
end

-- Scan all objects in a room and start timers for any with timed_events.
-- Called on room load.
function fsm.scan_room_timers(registry, room)
    if not room or not room.contents then return end
    for _, obj_id in ipairs(room.contents) do
        -- Resume paused timer if available, otherwise start fresh
        if fsm.paused_timers[obj_id] then
            fsm.resume_timer(obj_id)
        else
            fsm.start_timer(registry, obj_id)
        end
        -- Also check surface/container contents
        local obj = registry:get(obj_id)
        if obj and obj.surfaces then
            for _, zone in pairs(obj.surfaces) do
                for _, item_id in ipairs(zone.contents or {}) do
                    if fsm.paused_timers[item_id] then
                        fsm.resume_timer(item_id)
                    else
                        fsm.start_timer(registry, item_id)
                    end
                end
            end
        end
        if obj and obj.contents then
            for _, item_id in ipairs(obj.contents) do
                if fsm.paused_timers[item_id] then
                    fsm.resume_timer(item_id)
                else
                    fsm.start_timer(registry, item_id)
                end
            end
        end
    end
end

-- Pause all timers for objects in a room. Called on room unload.
function fsm.pause_room_timers(room)
    if not room or not room.contents then return end
    for _, obj_id in ipairs(room.contents) do
        fsm.pause_timer(obj_id)
    end
end

-- Tick all active timers by delta_seconds.
-- Fires auto-transitions when timers expire.
-- Returns a list of { obj_id, message } for any transitions that fired.
function fsm.tick_timers(registry, delta_seconds)
    local messages = {}
    local expired = {}
    -- Phase 1: decrement and collect expired timers
    for obj_id, timer in pairs(fsm.active_timers) do
        timer.remaining = timer.remaining - delta_seconds
        if timer.remaining <= 0 then
            expired[#expired + 1] = { id = obj_id, timer = timer }
        else
            -- Update remaining_burn on the object for save/resume fidelity
            local obj = registry:get(obj_id)
            if obj and obj.remaining_burn then
                obj.remaining_burn = timer.remaining
            end
        end
    end
    -- Phase 2: process expired timers (safe to mutate active_timers now)
    for _, entry in ipairs(expired) do
        local obj_id = entry.id
        local timer = entry.timer
        fsm.active_timers[obj_id] = nil
        local obj = registry:get(obj_id)
        if obj and obj._state == timer.state then
            -- Update remaining_burn if object tracks it
            if obj.remaining_burn then
                obj.remaining_burn = 0
            end
            -- Fire the auto-transition
            for _, t in ipairs(obj.transitions or {}) do
                if t.from == timer.state and t.trigger == "auto"
                   and t.condition == "timer_expired" then
                    apply_state(obj, t.to, timer.state)
                    apply_mutations(obj, t.mutate)
                    if t.message then
                        messages[#messages + 1] = { obj_id = obj_id, message = t.message }
                    end
                    break
                end
            end
            -- Start new timer if the new state also has timed_events (cyclic clocks)
            fsm.start_timer(registry, obj_id)
        end
    end
    return messages
end

return fsm

end

package.preload["engine.loader"] = function()
-- engine/loader/init.lua
-- Sandboxed loader: accepts a Lua source string, returns a live table.
-- The sandbox deliberately excludes os, io, and other dangerous globals.
-- Also handles template resolution -- merging base templates under instances.

local loader = {}

-- Minimal safe environment available to all loaded object code.
local function make_sandbox()
  return {
    ipairs   = ipairs,
    pairs    = pairs,
    next     = next,
    select   = select,
    tonumber = tonumber,
    tostring = tostring,
    type     = type,
    unpack   = unpack or table.unpack,
    error    = error,
    pcall    = pcall,
    math     = math,
    string   = string,
    table    = table,
  }
end

-- deep_merge(base, override) -> merged table
-- Copies all fields from base into a new table, then overlays override on top.
-- Nested tables are recursively merged (arrays are replaced, not appended).
-- The override always wins for any key it defines.
local function deep_merge(base, override)
  local result = {}

  -- Copy base values
  for k, v in pairs(base) do
    if type(v) == "table" then
      result[k] = deep_merge(v, {})
    else
      result[k] = v
    end
  end

  -- Overlay override values
  for k, v in pairs(override) do
    if type(v) == "table" and type(result[k]) == "table" then
      result[k] = deep_merge(result[k], v)
    else
      result[k] = v
    end
  end

  return result
end

-- load_source(source) -> table, nil  |  nil, error_string
-- Executes `source` inside the sandbox and returns whatever the chunk returns.
-- The source is expected to return a Lua table (the object definition).
function loader.load_source(source)
  local env = make_sandbox()

  -- Lua 5.1 uses loadstring; 5.2+ uses load() with an env argument.
  local chunk, err
  if _VERSION == "Lua 5.1" then
    chunk, err = loadstring(source)
    if chunk then setfenv(chunk, env) end
  else
    chunk, err = load(source, "object", "t", env)
  end

  if not chunk then
    return nil, "compile error: " .. tostring(err)
  end

  local ok, result = pcall(chunk)
  if not ok then
    return nil, "runtime error: " .. tostring(result)
  end

  if type(result) ~= "table" then
    return nil, "object source must return a table, got " .. type(result)
  end

  return result, nil
end

-- resolve_template(object, templates) -> resolved_object, nil | nil, error_string
-- If the object has a `template` field, looks up the template by id in the
-- templates table and merges base properties under the instance's overrides.
-- The instance always wins. The `template` field is removed after resolution.
function loader.resolve_template(object, templates)
  if not object.template then
    return object, nil
  end

  local template_id = object.template
  local tmpl = templates[template_id]
  if not tmpl then
    return nil, "template '" .. tostring(template_id) .. "' not found"
  end

  local resolved = deep_merge(tmpl, object)
  resolved.template = nil  -- consumed; no longer needed at runtime
  return resolved, nil
end

-- load_template(source) -> table, nil | nil, error_string
-- Convenience: loads a template source string. Identical to load_source,
-- but named separately for clarity in calling code.
function loader.load_template(source)
  return loader.load_source(source)
end

-- resolve_instance(instance, base_classes, templates) -> resolved_object, nil | nil, error_string
-- Takes an instance definition (with type_id and optional overrides),
-- looks up the base class by GUID, deep-merges overrides on top,
-- and prepares the object for registration.
-- Contents arrays are cleared -- they are rebuilt from the instance tree.
function loader.resolve_instance(instance, base_classes, templates)
  if not instance.type_id then
    return nil, "instance '" .. tostring(instance.id) .. "' missing type_id"
  end

  local base = base_classes[instance.type_id]
  if not base then
    return nil, "base class not found for guid '" .. instance.type_id
        .. "' (instance '" .. tostring(instance.id) .. "')"
  end

  -- Deep-copy base, then overlay instance overrides
  local resolved = deep_merge(base, instance.overrides or {})

  -- Resolve template if base was not pre-resolved
  if resolved.template then
    local tmpl_resolved, err = loader.resolve_template(resolved, templates or {})
    if not tmpl_resolved then
      return nil, err
    end
    resolved = tmpl_resolved
  end

  -- Instance identity overrides base identity
  resolved.id = instance.id
  resolved.type_id = instance.type_id
  resolved.guid = nil  -- guid belongs to the base class, not the instance

  -- Clear contents -- these are rebuilt from the instance tree.
  -- Preserve the field if the base class defined it (for on_look etc.)
  if resolved.contents ~= nil then
    resolved.contents = {}
  end
  if resolved.surfaces then
    for _, zone in pairs(resolved.surfaces) do
      zone.contents = {}
    end
  end

  return resolved, nil
end

return loader

end

package.preload["engine.loop"] = function()
-- engine/loop/init.lua
-- Terminal REPL game loop.
-- Routes player input through the parser pipeline and dispatches to verb handlers.
--
-- Ownership:
--   Smithers (UI Engineer): REPL I/O, parse pipeline (Tier 1→2→3), scroll, quit
--   Bart (Architect): Post-command FSM tick phase, timed events
--
-- Parser pipeline lives in engine/parser/preprocess.lua (Smithers owns).

local loop = {}

-- Parser preprocessing (Smithers owns — see engine/parser/preprocess.lua)
local preprocess = require("engine.parser.preprocess")

-- Tier 3: goal-oriented prerequisite planner (optional module)
local planner_ok, goal_planner = pcall(require, "engine.parser.goal_planner")
if not planner_ok then goal_planner = nil end

-- run(context)
-- context fields:
--   registry     -- live registry instance
--   current_room -- room table (must have .id, .name, .description)
--   verbs        -- table of { [verb_string] = handler_function }
--   ui           -- (optional) engine.ui module instance
--   on_quit      -- optional callback fired before exit
-- BUG-060: Pronouns that resolve to the last referenced noun
local PRONOUNS = {
  it = true, them = true, that = true, this = true, those = true,
  ["the same"] = true, ["the same thing"] = true,
}

function loop.run(context)
  assert(context and context.registry, "loop: context.registry is required")
  context.verbs = context.verbs or {}

  -- Context tracking for Tier 3 planner
  context.last_tool = context.last_tool or nil
  context.known_objects = context.known_objects or {}

  -- BUG-060: last referenced noun for context retention between commands
  context.last_noun = context.last_noun or nil

  -- Session transcript for "report bug" (last 50 exchanges)
  context.transcript = context.transcript or {}

  print("Type 'look' to look around. Type 'report bug' to report issues. Type 'quit' to exit.")
  if context.ui and context.ui.is_enabled() then
    print("Scroll: /up  /down  /bottom")
  end
  print("")

  while true do
    -- Update status bar if UI is active
    if context.ui and context.ui.is_enabled() and context.update_status then
      context.update_status(context)
    end

    -- Read input (UI-aware or fallback)
    local input
    if context.ui and context.ui.is_enabled() then
      input = context.ui.input()
    else
      io.write("> ")
      io.flush()
      input = io.read()
    end
    if not input then break end -- EOF / piped input exhausted

    local trimmed = input:match("^%s*(.-)%s*$")
    if trimmed == "" then goto continue end

    -- Handle scroll commands before game processing
    if context.ui and context.ui.handle_scroll(trimmed) then
      goto continue
    end

    -- Echo command into the output window
    if context.ui and context.ui.is_enabled() then
      context.ui.output("> " .. trimmed)
    end

    -- Strip trailing question marks before parsing
    trimmed = trimmed:gsub("%?+$", ""):match("^%s*(.-)%s*$")
    if trimmed == "" then goto continue end

    -- Multi-command splitting: commas, semicolons, "then" (Issue #1)
    local command_parts = preprocess.split_commands(trimmed)

    -- Expand each part further with the existing " and " compound split
    local sub_commands = {}
    for _, part in ipairs(command_parts) do
      local remaining = part
      while true do
        local before, after = remaining:match("^(.-)%s+and%s+(.+)$")
        if before and after then
          local b = before:match("^%s*(.-)%s*$")
          if b ~= "" then sub_commands[#sub_commands + 1] = b end
          remaining = after
        else
          local r = remaining:match("^%s*(.-)%s*$")
          if r ~= "" then sub_commands[#sub_commands + 1] = r end
          break
        end
      end
    end

    -- If compound command's last part has a GOAP plan, let GOAP handle everything.
    -- e.g. "get match from matchbox and light candle" → GOAP plans "light candle"
    -- end-to-end, making the first part redundant.
    if #sub_commands > 1 and goal_planner then
      local last = sub_commands[#sub_commands]
      local lv, ln = preprocess.natural_language(last)
      if not lv then lv, ln = preprocess.parse(last) end
      if lv == "light" or lv == "ignite" or lv == "burn" then
        local clean = ln:match("^(.-)%s+with%s+.+$")
        if clean and clean ~= "" then ln = clean end
      end
      local plan = goal_planner.plan(lv, ln, context)
      if plan and #plan > 0 then
        sub_commands = { last }
      end
    end

    local should_quit = false
    for _, sub_input in ipairs(sub_commands) do
      -- Try natural language preprocessing first (Smithers's parser pipeline)
      local verb, noun = preprocess.natural_language(sub_input)
      if not verb then
        verb, noun = preprocess.parse(sub_input)
      end

      if verb == "" then goto next_sub end

      if verb == "quit" then
        should_quit = true
        break
      end

      -- BUG-060: Context noun resolution — resolve pronouns and empty nouns
      -- Verbs that operate on the room (no noun expected) are excluded.
      local no_noun_verbs = {
        look = true, feel = true, smell = true, listen = true, taste = true,
        inventory = true, i = true, help = true, time = true, quit = true,
        sleep = true, rest = true, nap = true, wait = true, score = true,
        report_bug = true,
        -- Direction verbs should never inherit a context noun
        north = true, south = true, east = true, west = true,
        up = true, down = true, n = true, s = true, e = true, w = true,
        u = true, d = true, go = true, enter = true, walk = true, run = true,
        climb = true, ascend = true, descend = true,
        -- Drop/put verbs inherit noun correctly from their own grammar
        drop = true,
      }
      if noun ~= "" and PRONOUNS[noun] and context.last_noun then
        noun = context.last_noun
      elseif noun == "" and context.last_noun and not no_noun_verbs[verb] then
        noun = context.last_noun
      end

      -- Prepositional parsing: strip "with Y" for verbs that auto-find tools
      if verb == "light" or verb == "ignite" or verb == "burn" then
        local clean_noun = noun:match("^(.-)%s+with%s+.+$")
        if clean_noun and clean_noun ~= "" then noun = clean_noun end
      end

      -- Tier 3: goal-oriented prerequisite planning
      if goal_planner then
        local plan = goal_planner.plan(verb, noun, context)
        if plan then
          if not goal_planner.execute(plan, context) then
            goto next_sub
          end
        end
      end

      -- Capture print output for transcript recording (BUG-060 / report bug)
      local old_print = _G.print
      local response_lines = {}
      _G.print = function(...)
        local parts = {}
        for i = 1, select("#", ...) do
          parts[i] = tostring(select(i, ...))
        end
        local line = table.concat(parts, "\t")
        response_lines[#response_lines + 1] = line
        old_print(...)
      end

      local handler = context.verbs[verb]
      if handler then
        handler(context, noun)
        -- BUG-060: Update last_noun after successful handler with a real noun
        if noun ~= "" and not no_noun_verbs[verb] then
          -- Strip prepositions for context: "in wardrobe" → "wardrobe"
          local bare = noun:match("^%a+%s+(.+)$")
          context.last_noun = bare or noun
        end
      elseif context.parser then
        -- Tier 2 fallback: try embedding-based phrase matching
        local parser_fallback = require("engine.parser")
        local handled = parser_fallback.fallback(context.parser, sub_input, context)
        if not handled then
          -- Tier 2 failed — restore print and skip
          _G.print = old_print
          goto next_sub
        end
      else
        -- No Tier 2 available -- original behaviour
        local question_words = { what = true, where = true, how = true, who = true, why = true }
        if question_words[verb] then
          print("Try 'feel' to explore by touch, or 'look' if you have light. Type 'help' for a full list of commands.")
        else
          print("I don't understand '" .. verb .. "'. Try 'look', 'examine', 'take', 'open', or type 'help' for a full list.")
        end
      end

      -- Restore print and record transcript entry
      _G.print = old_print
      if #response_lines > 0 then
        local entry = {
          input = sub_input,
          output = table.concat(response_lines, "\n"),
        }
        local transcript = context.transcript
        transcript[#transcript + 1] = entry
        -- Keep only last 50 exchanges
        while #transcript > 50 do
          table.remove(transcript, 1)
        end
      end

      ::next_sub::
    end

    if should_quit then
      if context.on_quit then context.on_quit() end
      print("Goodbye.")
      break
    end

    -- Post-command FSM tick phase: process auto-transitions (burn countdown, etc.)
    local fsm_ok, fsm_mod = pcall(require, "engine.fsm")
    if fsm_ok and fsm_mod and context.registry then
      local tick_targets = {}
      local reg = context.registry
      local room = context.current_room
      -- Room contents + their surface/container contents
      for _, obj_id in ipairs(room and room.contents or {}) do
        tick_targets[#tick_targets + 1] = obj_id
        local obj = reg:get(obj_id)
        if obj and obj.surfaces then
          for _, zone in pairs(obj.surfaces) do
            for _, item_id in ipairs(zone.contents or {}) do
              tick_targets[#tick_targets + 1] = item_id
            end
          end
        end
        if obj and obj.contents then
          for _, item_id in ipairs(obj.contents) do
            tick_targets[#tick_targets + 1] = item_id
          end
        end
      end
      -- Player hands
      if context.player then
        for i = 1, 2 do
          if context.player.hands[i] then
            tick_targets[#tick_targets + 1] = context.player.hands[i]
          end
        end
      end
      -- Tick all FSM objects (legacy on_tick callbacks + threshold checks)
      -- Build environment context from room properties for threshold evaluation
      local env_context = {
          temperature = room and room.temperature or 20,
          wetness = room and room.wetness or 0,
          moisture = room and room.moisture or 0,
          light_level = room and room.light_level or 0,
      }
      for _, obj_id in ipairs(tick_targets) do
        local obj = reg:get(obj_id)
        if obj and obj._state then
          local msg = fsm_mod.tick(reg, obj_id, env_context)
          if msg then
            print("")
            print(msg)
          end
        end
      end

      -- Timed events engine: each command tick = 360 game seconds
      -- (consistent with SLEEP: 10 ticks per game hour = 3600s / 10 = 360s)
      local SECONDS_PER_TICK = 360
      local timer_msgs = fsm_mod.tick_timers(reg, SECONDS_PER_TICK)
      for _, entry in ipairs(timer_msgs) do
        print("")
        print(entry.message)
        -- Remove spent consumables from player's hands after auto-transition
        if context.player then
          local obj = reg:get(entry.obj_id)
          if obj and obj._state then
            local st = obj.states and obj.states[obj._state]
            if st and st.terminal and st.consumable then
              for i = 1, 2 do
                if context.player.hands[i] == entry.obj_id then
                  context.player.hands[i] = nil
                end
              end
              if context.current_room then
                context.current_room.contents[#context.current_room.contents + 1] = entry.obj_id
                obj.location = context.current_room.id
              end
            end
          end
        end
      end
    end

    -- Post-command tick (flame countdown, candle burn, etc.)
    if context.on_tick then
      context.on_tick(context)
    end

    -- Game over check (death by poison, etc.)
    if context.game_over then
      print("")
      print("Game over. Thanks for playing.")
      break
    end

    ::continue::
  end
end

return loop

end

