-- engine/parser/json.lua
-- Minimal JSON decoder for loading the embedding index.
-- Supports: objects, arrays, strings, numbers, booleans, null.
-- Not a general-purpose JSON library -- just enough for our index format.

local json = {}

local function skip_ws(s, i)
  return s:match("^%s*()", i)
end

local function decode_string(s, i)
  -- i points at the opening "
  assert(s:sub(i, i) == '"', "expected '\"' at position " .. i)
  local j = i + 1
  local parts = {}
  while j <= #s do
    local c = s:sub(j, j)
    if c == '"' then
      return table.concat(parts), j + 1
    elseif c == '\\' then
      j = j + 1
      local esc = s:sub(j, j)
      if esc == '"' or esc == '\\' or esc == '/' then
        parts[#parts + 1] = esc
      elseif esc == 'n' then parts[#parts + 1] = '\n'
      elseif esc == 'r' then parts[#parts + 1] = '\r'
      elseif esc == 't' then parts[#parts + 1] = '\t'
      elseif esc == 'b' then parts[#parts + 1] = '\b'
      elseif esc == 'f' then parts[#parts + 1] = '\f'
      elseif esc == 'u' then
        -- Basic \uXXXX -- just pass through as-is for ASCII range
        local hex = s:sub(j + 1, j + 4)
        local cp = tonumber(hex, 16)
        if cp and cp < 128 then
          parts[#parts + 1] = string.char(cp)
        else
          parts[#parts + 1] = "?" -- non-ASCII placeholder
        end
        j = j + 4
      end
    else
      parts[#parts + 1] = c
    end
    j = j + 1
  end
  error("unterminated string at position " .. i)
end

local decode_value -- forward declaration

local function decode_array(s, i)
  -- i points at [
  i = skip_ws(s, i + 1)
  local arr = {}
  if s:sub(i, i) == ']' then return arr, i + 1 end
  while true do
    local val
    val, i = decode_value(s, i)
    arr[#arr + 1] = val
    i = skip_ws(s, i)
    local c = s:sub(i, i)
    if c == ']' then return arr, i + 1 end
    assert(c == ',', "expected ',' or ']' at position " .. i)
    i = skip_ws(s, i + 1)
  end
end

local function decode_object(s, i)
  -- i points at {
  i = skip_ws(s, i + 1)
  local obj = {}
  if s:sub(i, i) == '}' then return obj, i + 1 end
  while true do
    local key
    key, i = decode_string(s, i)
    i = skip_ws(s, i)
    assert(s:sub(i, i) == ':', "expected ':' at position " .. i)
    i = skip_ws(s, i + 1)
    local val
    val, i = decode_value(s, i)
    obj[key] = val
    i = skip_ws(s, i)
    local c = s:sub(i, i)
    if c == '}' then return obj, i + 1 end
    assert(c == ',', "expected ',' or '}' at position " .. i)
    i = skip_ws(s, i + 1)
  end
end

decode_value = function(s, i)
  i = skip_ws(s, i)
  local c = s:sub(i, i)
  if c == '"' then return decode_string(s, i)
  elseif c == '{' then return decode_object(s, i)
  elseif c == '[' then return decode_array(s, i)
  elseif c == 't' then
    assert(s:sub(i, i + 3) == 'true')
    return true, i + 4
  elseif c == 'f' then
    assert(s:sub(i, i + 4) == 'false')
    return false, i + 5
  elseif c == 'n' then
    assert(s:sub(i, i + 3) == 'null')
    return nil, i + 4
  else
    -- number
    local num_str = s:match("^-?%d+%.?%d*[eE]?[%+%-]?%d*", i)
    assert(num_str, "unexpected character at position " .. i .. ": '" .. c .. "'")
    return tonumber(num_str), i + #num_str
  end
end

function json.decode(s)
  local val, _ = decode_value(s, 1)
  return val
end

return json

end

package.preload["engine.parser.preprocess"] = function()
-- engine/parser/preprocess.lua
-- Input preprocessing pipeline: natural language normalization and basic parsing.
-- Owned by Smithers (UI Engineer). Pure functions, no side effects.
--
-- Extracts:
--   preprocess.natural_language(input) -> verb, noun or nil, nil
--   preprocess.parse(input) -> verb, noun

local preprocess = {}

--- parse(input) -> verb, noun
--- Splits a raw input string into the first word (verb) and the rest (noun).
--- Handles leading "I" pronoun: "i" is inventory only when typed alone.
function preprocess.parse(input)
    input = input:match("^%s*(.-)%s*$") -- trim
    local verb, noun = input:match("^(%S+)%s*(.*)")
    verb = (verb or ""):lower()
    noun = (noun or ""):lower()
    -- BUG-036: "I" as pronoun, not inventory shortcut. Re-parse the rest.
    if verb == "i" and noun ~= "" then
        return preprocess.parse(noun)
    end
    return verb, noun
end

--- natural_language(input) -> verb, noun or nil, nil
--- Converts common question patterns and multi-word phrases into known verbs.
--- Returns nil, nil if no pattern matches (caller should fall through to parse).
function preprocess.natural_language(input)
    local lower = input:lower():match("^%s*(.-)%s*$")
    if not lower or lower == "" then return nil, nil end

    -- BUG-036: Strip "I want to / I need to / I'd like to" preambles
    local preamble_rest = lower:match("^i%s+want%s+to%s+(.+)")
        or lower:match("^i%s+need%s+to%s+(.+)")
        or lower:match("^i'?d%s+like%s+to%s+(.+)")
        or lower:match("^i%s+would%s+like%s+to%s+(.+)")
        or lower:match("^i'?ll%s+(.+)")
        or lower:match("^i%s+need%s+(.+)")
        or lower:match("^i%s+want%s+(.+)")
    if preamble_rest then
        local v2, n2 = preprocess.natural_language(preamble_rest)
        if v2 then return v2, n2 end
        return preprocess.parse(preamble_rest)
    end

    -- Question patterns → look
    -- BUG-037: added "what's around me" pattern
    if lower:match("^what%s+is%s+around")
        or lower:match("^what'?s%s+around")
        or lower:match("^what%s+do%s+i%s+see")
        or lower:match("^what%s+can%s+i%s+see")
        or lower:match("^where%s+am%s+i")
        or lower:match("^look%s+around$") then
        return "look", ""
    end

    -- Question patterns → time
    if lower:match("^what%s+time")
        or lower:match("^what%s+is%s+the%s+time") then
        return "time", ""
    end

    -- Question patterns → inventory
    -- BUG-038: added "what am I holding" pattern
    if lower:match("^what%s+am%s+i%s+carry")
        or lower:match("^what%s+am%s+i%s+hold")
        or lower:match("^what%s+do%s+i%s+have") then
        return "inventory", ""
    end

    -- Question patterns → look in (container queries with noun)
    local container_noun = lower:match("^what'?s%s+in%s+(.+)")
        or lower:match("^what%s+is%s+in%s+(.+)")
        or lower:match("^what'?s%s+inside%s+(.+)")
        or lower:match("^what%s+is%s+inside%s+(.+)")
    if container_noun then
        return "look", "in " .. container_noun
    end

    -- Bare "what's inside" (no noun) → look
    if lower:match("^what'?s%s+inside$")
        or lower:match("^what%s+is%s+inside$") then
        return "look", ""
    end

    -- Question patterns → help
    if lower:match("^what%s+can%s+i%s+do")
        or lower:match("^how%s+do%s+i") then
        return "help", ""
    end

    -- Grope/feel compound phrases → feel (room sweep)
    if lower:match("^grope%s+around%s+")
        or lower:match("^feel%s+around%s+") then
        return "feel", ""
    end

    -- BUG-049: "pry open X" → open X
    local pry_target = lower:match("^pry%s+open%s+(.+)")
    if pry_target then
        return "open", pry_target
    end

    -- "use crowbar/bar on X" → open X (lever tool to force open)
    local crowbar_target = lower:match("^use%s+crowbar%s+on%s+(.+)")
        or lower:match("^use%s+bar%s+on%s+(.+)")
        or lower:match("^use%s+pry%s*bar%s+on%s+(.+)")
    if crowbar_target then
        return "open", crowbar_target
    end

    -- "report bug" / "report a bug" → report_bug
    if lower:match("^report%s+a?%s*bug")
        or lower:match("^bug%s+report")
        or lower:match("^file%s+a?%s*bug") then
        return "report_bug", ""
    end

    -- Composite part phrases: "take out X", "pull out X" → pull
    local pull_target = lower:match("^take%s+out%s+(.+)")
        or lower:match("^pull%s+out%s+(.+)")
        or lower:match("^yank%s+out%s+(.+)")
    if pull_target then
        return "pull", pull_target
    end

    -- Spatial movement phrases: "roll up X" → move X
    local roll_target = lower:match("^roll%s+up%s+(.+)")
        or lower:match("^roll%s+(.+)%s+up$")
    if roll_target then
        return "move", roll_target
    end

    -- "pull back X" → move X
    local pullback_target = lower:match("^pull%s+back%s+(.+)")
    if pullback_target then
        return "move", pullback_target
    end

    -- "uncork X", "pop cork" → uncork
    local uncork_target = lower:match("^pop%s+(.+)")
    if uncork_target and uncork_target:match("cork") then
        return "uncork", "bottle"
    end

    -- "use X on Y" → sew Y with X (crafting shorthand)
    -- BUG-039: expanded to handle fire tools and generic "apply X to Y"
    local use_tool, use_target = lower:match("^use%s+(.+)%s+on%s+(.+)$")
    if use_tool and use_target then
        if use_tool:match("needle") or use_tool:match("thread") then
            return "sew", use_target .. " with " .. use_tool
        end
        if use_tool:match("key") then
            return "unlock", use_target .. " with " .. use_tool
        end
        if use_tool:match("match") or use_tool:match("lighter")
            or use_tool:match("flint") or use_tool:match("torch")
            or use_tool:match("fire") or use_tool:match("flame") then
            return "light", use_target .. " with " .. use_tool
        end
        -- Generic fallback: "use X on Y" → "apply" semantics via put
        return "put", use_tool .. " on " .. use_target
    end

    -- "push X back" / "put X back in Y" → put
    local push_back_target = lower:match("^push%s+(.+)%s+back")
    if push_back_target then
        return "put", push_back_target .. " in " .. push_back_target
    end

    -- "put X back" → put X in (context-dependent, let verb handler sort it)
    local put_back_item, put_back_target2 = lower:match("^put%s+(.+)%s+back%s+in%s+(.+)")
    if put_back_item then
        return "put", put_back_item .. " in " .. put_back_target2
    end

    -- Extinguish phrases: "put out X", "blow out X" → extinguish
    local extinguish_target = lower:match("^put%s+out%s+(.+)")
        or lower:match("^blow%s+out%s+(.+)")
    if extinguish_target then
        return "extinguish", extinguish_target
    end

    -- Wear/equip phrases: "put on X", "dress in X" → wear
    local wear_target = lower:match("^put%s+on%s+(.+)")
        or lower:match("^dress%s+in%s+(.+)")
    if wear_target then
        return "wear", wear_target
    end

    -- Remove/unequip phrases: "take off X" → remove
    local remove_target = lower:match("^take%s+off%s+(.+)")
    if remove_target then
        return "remove", remove_target
    end

    -- Wear query: "what am i wearing" → inventory
    if lower:match("^what%s+am%s+i%s+wear") then
        return "inventory", ""
    end

    -- Sleep phrases: "take a nap", "go to sleep", "lie down", "go to bed"
    if lower:match("^take%s+a%s+nap") then
        return "sleep", ""
    end
    local go_sleep_noun = lower:match("^go%s+to%s+sleep%s*(.*)")
    if go_sleep_noun then
        return "sleep", go_sleep_noun
    end
    if lower:match("^go%s+to%s+bed") then
        return "sleep", ""
    end
    if lower:match("^lie%s+down") then
        return "sleep", ""
    end

    -- Movement phrases: stairs, through, into
    if lower:match("^go%s+down%s+the%s+stair")
        or lower:match("^climb%s+down%s+the%s+stair")
        or lower:match("^descend%s+the%s+stair")
        or lower:match("^descend%s+stair") then
        return "down", ""
    end
    if lower:match("^go%s+up%s+the%s+stair")
        or lower:match("^climb%s+up%s+the%s+stair")
        or lower:match("^ascend%s+the%s+stair")
        or lower:match("^ascend%s+stair") then
        return "up", ""
    end

    -- Clock adjustment phrases: "turn hands", "set clock", "adjust clock"
    local clock_target = lower:match("^turn%s+hands%s*(.*)$")
        or lower:match("^turn%s+the%s+hands%s*(.*)$")
    if clock_target then
        local target = clock_target ~= "" and clock_target or "clock"
        return "set", target
    end
    if lower:match("^adjust%s+the%s+clock") or lower:match("^adjust%s+clock") then
        return "set", "clock"
    end
    if lower:match("^set%s+the%s+clock") or lower:match("^set%s+clock") then
        return "set", "clock"
    end

    return nil, nil
end

---------------------------------------------------------------------------
-- BUG-056: Plural-to-singular mapping for noun resolution.
-- Room descriptions use plurals ("torches", "portraits") but objects have
-- singular keywords. Returns a list of candidate singular forms to try.
---------------------------------------------------------------------------
local function singularize_word(word)
    if not word or #word < 3 then return {} end
    local forms = {}
    -- -ies → -y (berries → berry, entries → entry)
    local ies_stem = word:match("^(.+)ies$")
    if ies_stem and #ies_stem >= 1 then forms[#forms+1] = ies_stem .. "y" end
    -- -es → strip, only after sibilants: ch, sh, s, x, z
    -- (torches → torch, boxes → box, matches → match)
    local es_stem = word:match("^(.+)es$")
    if es_stem and #es_stem >= 2
        and (es_stem:match("ch$") or es_stem:match("sh$")
             or es_stem:match("[sxz]$")) then
        forms[#forms+1] = es_stem
    end
    -- -s → strip, but not -ss (portraits → portrait, candles → candle)
    local s_stem = word:match("^(.+[^s])s$")
    if s_stem and #s_stem >= 2 then forms[#forms+1] = s_stem end
    return forms
end

--- split_commands(input) -> list of command strings
--- Splits a raw input line on commas, semicolons, or the word "then" to support
--- multi-command input (e.g. "move bed, move rug, open trapdoor").
--- Trims whitespace from each segment and drops empty segments.
--- Does NOT split on separators inside double-quoted text.
function preprocess.split_commands(input)
    if not input then return {} end
    local trimmed = input:match("^%s*(.-)%s*$")
    if trimmed == "" then return {} end

    -- Fast path: no separators at all → single command
    if not trimmed:find("[,;]") and not trimmed:lower():find("%f[%a]then%f[%A]") then
        return { trimmed }
    end

    -- Tokenise respecting double-quoted regions
    local segments = {}
    local current = {}
    local in_quote = false
    local lower = trimmed:lower()
    local i = 1
    local len = #trimmed

    while i <= len do
        local ch = trimmed:sub(i, i)

        -- Toggle quote state
        if ch == '"' then
            in_quote = not in_quote
            current[#current + 1] = ch
            i = i + 1

        -- Comma or semicolon separator (outside quotes)
        elseif not in_quote and (ch == ',' or ch == ';') then
            local seg = table.concat(current):match("^%s*(.-)%s*$")
            if seg ~= "" then segments[#segments + 1] = seg end
            current = {}
            i = i + 1

        -- " then " word separator (outside quotes)
        elseif not in_quote and lower:sub(i, i + 5) == " then " then
            local seg = table.concat(current):match("^%s*(.-)%s*$")
            if seg ~= "" then segments[#segments + 1] = seg end
            current = {}
            i = i + 6  -- skip " then "

        else
            current[#current + 1] = ch
            i = i + 1
        end
    end

    -- Flush last segment
    local seg = table.concat(current):match("^%s*(.-)%s*$")
    if seg ~= "" then segments[#segments + 1] = seg end

    -- If splitting produced nothing useful, return original as single command
    if #segments == 0 then return { trimmed } end
    return segments
end

--- singularize(noun) -> table of singular form candidates
--- For multi-word nouns, also tries singularizing the last word.
function preprocess.singularize(noun)
    if not noun or #noun < 3 then return {} end
    noun = noun:lower()
    local forms = singularize_word(noun)
    -- Multi-word: also try singularizing just the last word
    local prefix, last = noun:match("^(.+%s)(%S+)$")
    if prefix then
        for _, s in ipairs(singularize_word(last)) do
            forms[#forms+1] = prefix .. s
        end
    end
    return forms
end

return preprocess

end

package.preload["engine.registry"] = function()
-- engine/registry/init.lua
-- The universe's object store: id -> live object table.
-- Every live object in a universe is registered here.
-- Supports weight tracking and category-based queries.

local registry = {}
registry.__index = registry

-- new() -> registry instance
function registry.new()
  return setmetatable({ _objects = {}, _guid_index = {} }, registry)
end

-- register(id, object) -- adds or replaces an object; stamps the id onto the object.
-- Also indexes by guid if the object has one.
function registry:register(id, object)
  assert(type(id) == "string" and id ~= "", "registry: id must be a non-empty string")
  assert(type(object) == "table", "registry: object must be a table")
  object.id = id
  self._objects[id] = object
  if type(object.guid) == "string" and object.guid ~= "" then
    self._guid_index[object.guid] = id
  end
end

-- get(id) -> object | nil
function registry:get(id)
  return self._objects[id]
end

-- find_by_guid(guid) -> object | nil
-- Looks up an object by its definition guid using the guid index.
function registry:find_by_guid(guid)
  local id = self._guid_index[guid]
  if id then return self._objects[id] end
  return nil
end

-- remove(id) -> removed object | nil
function registry:remove(id)
  local obj = self._objects[id]
  if obj and type(obj.guid) == "string" then
    self._guid_index[obj.guid] = nil
  end
  self._objects[id] = nil
  return obj
end

-- list() -> array of all live objects (order undefined)
function registry:list()
  local result = {}
  for _, obj in pairs(self._objects) do
    result[#result + 1] = obj
  end
  return result
end

-- find_by_keyword(keyword) -> first matching object | nil
-- Matches against object.keywords (array of strings) and object.name.
-- BUG-056: also tries singular forms of plural nouns.
function registry:find_by_keyword(keyword)
  local preprocess = require("engine.parser.preprocess")
  local kw = keyword:lower()
  local candidates = { kw }
  for _, s in ipairs(preprocess.singularize(kw)) do
    candidates[#candidates + 1] = s
  end
  for _, try_kw in ipairs(candidates) do
    for _, obj in pairs(self._objects) do
      if obj.name and obj.name:lower() == try_kw then
        return obj
      end
      if type(obj.keywords) == "table" then
        for _, k in ipairs(obj.keywords) do
          if k:lower() == try_kw then return obj end
        end
      end
    end
  end
  return nil
end

-- find_by_category(category) -> array of matching objects
-- Returns all objects that have the given category in their categories list.
function registry:find_by_category(category)
  local result = {}
  local cat = category:lower()
  for _, obj in pairs(self._objects) do
    if type(obj.categories) == "table" then
      for _, c in ipairs(obj.categories) do
        if c:lower() == cat then
          result[#result + 1] = obj
          break
        end
      end
    end
  end
  return result
end

-- total_weight(location_id) -> number
-- Sums the weight of all objects at a given location.
-- Useful for room weight limits or structural checks.
function registry:total_weight(location_id)
  local total = 0
  for _, obj in pairs(self._objects) do
    if obj.location == location_id then
      total = total + (obj.weight or 0)
    end
  end
  return total
end

-- contents_weight(container_id, surface_name) -> number
-- Sums the weight of all objects inside a container (or a specific surface).
function registry:contents_weight(container_id, surface_name)
  local container_obj = self._objects[container_id]
  if not container_obj then return 0 end

  local contents = {}
  if surface_name and container_obj.surfaces and container_obj.surfaces[surface_name] then
    contents = container_obj.surfaces[surface_name].contents or {}
  else
    contents = container_obj.contents or {}
  end

  local total = 0
  for _, item_id in ipairs(contents) do
    local obj = self._objects[item_id]
    if obj then
      total = total + (obj.weight or 0)
    end
  end
  return total
end

return registry

end

package.preload["engine.traverse_effects"] = function()
-- engine/traverse_effects.lua
-- Extensible on_traverse exit-effect engine.
--
-- When a player moves through an exit, the engine checks for an optional
-- on_traverse table on that exit. If present, it dispatches to a registered
-- handler based on the effect's `type` field.
--
-- Ownership: Bart (Architect)
-- Decision: D-TRAVERSE001 — on_traverse exit-effect pattern
--
-- Usage in room metadata:
--   exits = {
--     up = {
--       target = "storage-cellar",
--       on_traverse = {
--         type = "wind_effect",
--         description = "A cold draft rushes up the stairway...",
--         extinguishes = { "candle" }
--       }
--     }
--   }

local traverse_effects = {}

-- Registry of effect handlers keyed by type string.
-- Each handler: function(effect, ctx) -> nil
-- Handlers print their own messages and mutate state via ctx.
local handlers = {}

--- Register a new on_traverse effect handler.
-- @param effect_type  string   The `type` value that triggers this handler.
-- @param handler_fn   function(effect, ctx)  Called when the effect fires.
function traverse_effects.register(effect_type, handler_fn)
    handlers[effect_type] = handler_fn
end

--- Normalize an on_traverse table into { type = ..., ...fields }.
-- Accepts two formats:
--   1. Flat:   { type = "wind_effect", extinguishes = {...}, ... }
--   2. Nested: { wind_effect = { extinguishes = {...}, ... } }
-- Returns the normalized effect table, or nil if unrecognized.
local function normalize_effect(raw)
    if raw.type then return raw end

    -- Nested format: single key whose value is the effect payload
    local effect_type, payload
    for k, v in pairs(raw) do
        if type(v) == "table" then
            if effect_type then return nil end  -- ambiguous: multiple keys
            effect_type = k
            payload = v
        end
    end
    if not effect_type then return nil end

    -- Merge into flat format expected by handlers
    local flat = { type = effect_type }
    for k, v in pairs(payload) do flat[k] = v end
    return flat
end

--- Process an exit's on_traverse effects, if any.
-- Called by the movement handler BEFORE the player is moved.
-- @param exit  table|string  The exit definition from room metadata.
-- @param ctx   table         The game context (registry, player, etc.)
function traverse_effects.process(exit, ctx)
    if type(exit) ~= "table" then return end
    local raw = exit.on_traverse
    if not raw then return end

    local effect = normalize_effect(raw)
    if not effect then return end

    local handler = handlers[effect.type]
    if not handler then return end

    handler(effect, ctx)
end

---------------------------------------------------------------------------
-- Built-in handler: wind_effect
--
-- Checks player inventory for items in the `extinguishes` list.
-- If a matching item is found AND is in a "lit" state AND is NOT
-- wind_resistant, transitions it to "extinguished" (or "unlit") state.
---------------------------------------------------------------------------
local function wind_effect_handler(effect, ctx)
    local fsm_mod = require("engine.fsm")
    local presentation = require("engine.ui.presentation")

    local carried_ids = presentation.get_all_carried_ids(ctx)
    local extinguish_set = {}
    for _, name in ipairs(effect.extinguishes or {}) do
        extinguish_set[name:lower()] = true
    end

    local something_extinguished = false
    local something_spared = false

    for _, obj_id in ipairs(carried_ids) do
        local obj = ctx.registry:get(obj_id)
        if obj then
            -- Check if this object is in the extinguishes list (by id or keywords)
            local targeted = false
            if obj.id and extinguish_set[obj.id:lower()] then
                targeted = true
            end
            if not targeted and type(obj.keywords) == "table" then
                for _, kw in ipairs(obj.keywords) do
                    if extinguish_set[kw:lower()] then
                        targeted = true
                        break
                    end
                end
            end

            if targeted and obj._state == "lit" then
                if obj.wind_resistant then
                    something_spared = true
                else
                    -- Try extinguished first, then unlit
                    local trans, err = fsm_mod.transition(
                        ctx.registry, obj_id, "extinguished", nil, "extinguish"
                    )
                    if not trans then
                        trans, err = fsm_mod.transition(
                            ctx.registry, obj_id, "unlit", nil, "extinguish"
                        )
                    end
                    if trans then
                        something_extinguished = true
                    end
                end
            elseif not targeted and obj._state == "lit" and obj.wind_resistant then
                -- Not in extinguish list but lit and wind-resistant — spared
                something_spared = true
            end
        end
    end

    -- Print messages: effect description first, then outcome
    if something_extinguished or something_spared then
        if effect.description then
            print(effect.description)
        end
    end
    if something_extinguished then
        print(effect.message_extinguish or "The draft snuffs out your flame!")
    end
    if something_spared and not something_extinguished then
        if effect.message_spared then
            print(effect.message_spared)
        end
    end
end

traverse_effects.register("wind_effect", wind_effect_handler)

return traverse_effects

end

package.preload["engine.ui"] = function()
-- engine/ui/init.lua
-- Split-screen terminal UI using ANSI escape codes.
--
-- Layout (H = terminal height):
--   Line 1        : Status bar (reverse video)
--   Lines 2..H-2  : Output window (scrollable history)
--   Line H-1      : Delimiter (dashes)
--   Line H        : Input line ("> " prompt)
--
-- Pure Lua + ANSI. No external C libs.  Windows 10+ compatible.
-- Falls back to plain print/read when ANSI is unavailable.

local ui = {}

---------------------------------------------------------------------------
-- ANSI helpers
---------------------------------------------------------------------------
local ESC = "\27"

local function csi(...)  return ESC .. "[" .. table.concat({...}) end
local function move_to(r, c) io.write(csi(r, ";", c or 1, "H")) end
local function clear_eol()   io.write(csi("K")) end
local function hide_cursor() io.write(csi("?25l")) end
local function show_cursor() io.write(csi("?25h")) end
local function reverse()     io.write(csi("7m")) end
local function reset_attr()  io.write(csi("0m")) end
local function clear_screen()io.write(csi("2J")) end
local function set_scroll_region(top, bot)
    io.write(csi(top, ";", bot, "r"))
end
local function reset_scroll_region() io.write(csi("r")) end

---------------------------------------------------------------------------
-- State (module-level, single instance)
---------------------------------------------------------------------------
local enabled      = false
local width        = 80
local height       = 24
local buffer       = {}     -- scrollback: array of wrapped lines
local max_buffer   = 500
local scroll_off   = 0     -- 0 = viewing bottom; positive = scrolled up
local stat_left    = ""
local stat_right   = ""

-- Computed geometry (set by compute_regions)
local out_top, out_bot, out_lines
local delim_row, input_row

local function compute_regions()
    out_top    = 2
    out_bot    = height - 2
    out_lines  = out_bot - out_top + 1
    delim_row  = height - 1
    input_row  = height
end

---------------------------------------------------------------------------
-- Terminal size detection
---------------------------------------------------------------------------
local function detect_size()
    local w, h = 80, 24
    if package.config:sub(1, 1) == "\\" then
        -- Windows: parse "mode con" output
        local ok, p = pcall(io.popen, "mode con 2>nul")
        if ok and p then
            local out = p:read("*a")
            p:close()
            local cols  = out:match("Columns:%s*(%d+)")
            local lines = out:match("Lines:%s*(%d+)")
            if cols  then w = tonumber(cols)  end
            if lines then h = tonumber(lines) end
        end
    else
        local ok, p = pcall(io.popen, "stty size 2>/dev/null")
        if ok and p then
            local out = p:read("*l")
            p:close()
            if out then
                local r, c = out:match("(%d+)%s+(%d+)")
                if r then h = tonumber(r) end
                if c then w = tonumber(c) end
            end
        end
    end
    return w, h
end

---------------------------------------------------------------------------
-- Word-wrap (replicates display.word_wrap logic for buffer lines)
---------------------------------------------------------------------------
local function wrap_text(text, w)
    w = w or width
    if not text then return { "" } end
    if text == "" then return { "" } end

    local lines = {}
    for segment in (text .. "\n"):gmatch("(.-)\n") do
        if segment == "" then
            lines[#lines + 1] = ""
        elseif #segment <= w then
            lines[#lines + 1] = segment
        else
            local indent = segment:match("^(%s*)") or ""
            local content = segment:sub(#indent + 1)
            local line = indent
            for word in content:gmatch("%S+") do
                if line == indent then
                    line = indent .. word
                elseif #line + 1 + #word > w then
                    lines[#lines + 1] = line
                    line = indent .. word
                else
                    line = line .. " " .. word
                end
            end
            if line ~= indent or line ~= "" then
                lines[#lines + 1] = line
            end
        end
    end
    -- gmatch artifact: trailing empty string from appended "\n"
    if #lines > 1 and lines[#lines] == "" and not text:match("\n$") then
        table.remove(lines)
    end
    if #lines == 0 then lines = { "" } end
    return lines
end

---------------------------------------------------------------------------
-- Drawing primitives
---------------------------------------------------------------------------

local function draw_status()
    move_to(1, 1)
    reverse()
    local left  = stat_left  or ""
    local right = stat_right or ""
    local pad   = width - #left - #right
    if pad < 1 then pad = 1 end
    local bar = left .. string.rep(" ", pad) .. right
    if #bar > width then bar = bar:sub(1, width) end
    io.write(bar)
    reset_attr()
end

local function draw_delimiter()
    move_to(delim_row, 1)
    clear_eol()
    io.write(string.rep("-", width))
end

local function redraw_output()
    local total   = #buffer
    local visible = out_lines
    local start_idx = total - visible - scroll_off + 1
    if start_idx < 1 then start_idx = 1 end

    for i = 0, visible - 1 do
        local buf_idx = start_idx + i
        local row     = out_top + i
        move_to(row, 1)
        clear_eol()
        if buf_idx >= 1 and buf_idx <= total then
            local line = buffer[buf_idx] or ""
            if #line > width then line = line:sub(1, width) end
            io.write(line)
        end
    end
end

local function draw_input_prompt(text)
    move_to(input_row, 1)
    clear_eol()
    io.write("> " .. (text or ""))
end

local function full_refresh()
    hide_cursor()
    draw_status()
    redraw_output()
    draw_delimiter()
    draw_input_prompt("")
    show_cursor()
    io.flush()
end

---------------------------------------------------------------------------
-- Buffer management
---------------------------------------------------------------------------
local function append_to_buffer(text)
    local lines = wrap_text(text, width)
    for _, line in ipairs(lines) do
        buffer[#buffer + 1] = line
        if #buffer > max_buffer then
            table.remove(buffer, 1)
            if scroll_off > 0 then scroll_off = scroll_off - 1 end
        end
    end
end

---------------------------------------------------------------------------
-- Public API
---------------------------------------------------------------------------

--- Initialise the split-screen UI.  Returns true on success.
function ui.init()
    width, height = detect_size()
    if height < 8 or width < 20 then
        -- Terminal too small for split-screen
        return false
    end

    compute_regions()
    buffer     = {}
    scroll_off = 0
    stat_left  = ""
    stat_right = ""
    enabled    = true

    -- Enable VT processing on Windows (harmless no-op if already active)
    if package.config:sub(1, 1) == "\\" then
        os.execute("")
    end

    clear_screen()
    -- Set scroll region to output area so Enter on input line won't scroll
    set_scroll_region(out_top, out_bot)
    full_refresh()
    return true
end

function ui.is_enabled()
    return enabled
end

function ui.get_width()
    return width
end

--- Print text into the output window (replaces raw print when UI is active).
function ui.output(text)
    if not enabled then
        io.write((text or "") .. "\n")
        io.flush()
        return
    end

    append_to_buffer(text or "")
    scroll_off = 0  -- snap to bottom on new output

    hide_cursor()
    redraw_output()
    show_cursor()
    io.flush()
end

--- Update the status bar.
function ui.status(left, right)
    stat_left  = left  or stat_left
    stat_right = right or stat_right
    if not enabled then return end
    hide_cursor()
    draw_status()
    show_cursor()
    io.flush()
end

--- Read one line from the input area.
--- Returns nil on EOF.
function ui.input()
    if not enabled then
        io.write("> ")
        io.flush()
        return io.read()
    end

    -- Position cursor at input line
    move_to(input_row, 1)
    clear_eol()
    io.write("> ")
    show_cursor()
    io.flush()

    local text = io.read()
    if not text then return nil end

    -- Immediately clear the input line to prevent stale echo
    move_to(input_row, 1)
    clear_eol()
    io.flush()

    return text
end

--- Sub-prompt (e.g., "What do you want to write? > ").
--- Shows msg in the output window, then reads from input line.
function ui.prompt(msg)
    if not enabled then
        io.write(msg)
        io.flush()
        return io.read()
    end

    ui.output(msg)
    return ui.input()
end

--- Scroll the output window up by n lines (default ≈ one page).
function ui.scroll_up(n)
    if not enabled then return end
    n = n or math.max(1, out_lines - 2)
    local max_scroll = math.max(0, #buffer - out_lines)
    scroll_off = math.min(scroll_off + n, max_scroll)
    hide_cursor()
    redraw_output()
    show_cursor()
    io.flush()
end

--- Scroll the output window down by n lines (default ≈ one page).
function ui.scroll_down(n)
    if not enabled then return end
    n = n or math.max(1, out_lines - 2)
    scroll_off = math.max(0, scroll_off - n)
    hide_cursor()
    redraw_output()
    show_cursor()
    io.flush()
end

--- Returns true (and handles it) if input is a scroll command.
function ui.handle_scroll(input)
    if not enabled then return false end
    local cmd = (input or ""):match("^%s*(.-)%s*$")
    if cmd == "/up" or cmd == "/pgup" then
        ui.scroll_up()
        return true
    elseif cmd == "/down" or cmd == "/pgdn" then
        ui.scroll_down()
        return true
    elseif cmd == "/bottom" then
        scroll_off = 0
        hide_cursor()
        redraw_output()
        show_cursor()
        io.flush()
        return true
    end
    return false
end

--- Full-screen refresh (status + output + delimiter + input prompt).
function ui.refresh()
    if not enabled then return end
    full_refresh()
end

--- Restore terminal to normal state.
function ui.cleanup()
    if not enabled then return end
    enabled = false
    reset_scroll_region()
    reset_attr()
    show_cursor()
    clear_screen()
    move_to(1, 1)
    io.flush()
end

return ui

end

