                    end
                end
            end
        end
    end
    -- Search held objects for parts
    for i = 1, 2 do
        local hand_id = ctx.player.hands[i]
        if hand_id then
            local obj = reg:get(hand_id)
            if obj and obj.parts then
                for part_key, part in pairs(obj.parts) do
